class Solution {
    public int minimizedStringLength(String s) {
        int result = 0;
        int prevLength = s.length();
        for (int i = 0; i < s.length(); i++) {
            if (isValid(s, i)) {
                int currLength = s.length();
                result = Math.min(result, currLength);
                prevLength = currLength;
            }
        }
        return result;
    }

    private boolean isValid(String s, int i) {
        if (i == 0 || i == s.length() - 1) {
            return true;
        }
        if (s.charAt(i) == s.charAt(i - 1)) {
            return true;
        }
        return false;
    }
}
